#include <stdio.h>
#include <stdbool.h>

static bool isPDS(long long x) {
    long long sum = 0, prod = 1;
    long long t = x;
    while (t > 0) {
        int d = t % 10;
        sum += d;
        prod *= d;
        t /= 10;
    }
    return prod % sum == 0;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long N;
        scanf("%lld", &N);
        long long count = 0;
        long long x = 1;
        while (1) {
            if (isPDS(x)) count++;
            if (count == N) {
                printf("%lld\n", x);
                break;
            }
            x++;
        }
    }
    return 0;
}

