#!/usr/bin/env python3
import sys

def is_pds(x: int) -> bool:
    s = 0
    p = 1
    while x:
        d = x % 10
        s += d
        p *= d
        x //= 10
    return p % s == 0

def main():
    T = int(sys.stdin.readline().strip())
    for _ in range(T):
        N = int(sys.stdin.readline().strip())
        count = 0
        x = 1
        while True:
            if is_pds(x):
                count += 1
            if count == N:
                sys.stdout.write(str(x) + '\n')
                break
            x += 1

if __name__ == "__main__":
    main()

